# @cctt_verify {"v":2,"sym":"sympy.printing.c.get_math_macros","kind":"function","src_hash":"528a1a32030ed661","in":{"base":"Any"},"out":{"base":"Any"},"spec":{"lhs":"get_math_macros()","rhs":"returns a dictionary with math-related macros from math.h/cmath","over":{"base":"Any"},"name":"get_math_macros_correct"},"guarantee":"returns a dictionary with math-related macros from math.h/cmath","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.printing.c.get_math_macros_correct","statement":"Path(get_math_macros(x), returns a dictionary with math-related macros from math.h/cmath)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"d5e79a50edfe3afa"}
def get_math_macros():
    """ Returns a dictionary with math-related macros from math.h/cmath

    Note that these macros are not strictly required by the C/C++-standard.
    For MSVC they are enabled by defining "_USE_MATH_DEFINES" (preferably
    via a compilation flag).

    Returns
    =======

    Dictionary mapping SymPy expressions to strings (macro names)

    """
    from sympy.codegen.cfunctions import log2, Sqrt
    from sympy.functions.elementary.exponential import log
    from sympy.functions.elementary.miscellaneous import sqrt

    return {
        S.Exp1: 'M_E',
        log2(S.Exp1): 'M_LOG2E',
        1/log(2): 'M_LOG2E',
        log(2): 'M_LN2',
        log(10): 'M_LN10',
        S.Pi: 'M_PI',
        S.Pi/2: 'M_PI_2',
        S.Pi/4: 'M_PI_4',
        1/S.Pi: 'M_1_PI',
        2/S.Pi: 'M_2_PI',
        2/sqrt(S.Pi): 'M_2_SQRTPI',
        2/Sqrt(S.Pi): 'M_2_SQRTPI',
        sqrt(2): 'M_SQRT2',
        Sqrt(2): 'M_SQRT2',
        1/sqrt(2): 'M_SQRT1_2',
        1/Sqrt(2): 'M_SQRT1_2'
    }


